define nofpclass(nan pinf zero norm) float @ret_ninf_or_sub__log_select__pinf_or_sub_orzero__else_not0__ieee(i1 %cond, float nofpclass(nan ninf norm) %must.be.pinf.or.sub.or.zero, float nofpclass(zero) %not.zero) {
  %select = select i1 %cond, float %must.be.pinf.or.sub.or.zero, float %not.zero
  %result = call float @llvm.log.f32(float %select)
  ret float %result
}

