  %select = select i1 %cond, float %must.be.finite.positive, float %unknown
  %result = call float @llvm.log.f32(float %select)
  ret float %result
}

define nofpclass(ninf) float @ret_nofpclass_ninf_log(i1 %cond, float %x, float nofpclass(inf sub norm) %zero) {
  %select = select i1 %cond, float %zero, float %x
  %result = call float @llvm.log.f32(float %select)
  ret float %result
}

define nofpclass(inf zero sub norm) float @ret_nofpclass_only_nan__log(float %unknown) {
  %result = call float @llvm.log.f32(float %unknown)
  ret float %result
}

